class Solution:
    def minimumCost(self, s, t, flipCost, swapCost, crossCost):
        a = 0
        b = 0
        for cs, ct in zip(s, t):
            if cs == '0' and ct == '1':
                a += 1
            elif cs == '1' and ct == '0':
                b += 1
        opposite_pair_cost = min(swapCost, 2 * flipCost)
        total = min(a, b) * opposite_pair_cost
        leftover = abs(a - b)
        same_pair_cost = min(2 * flipCost, swapCost + crossCost)
        total += (leftover // 2) * same_pair_cost
        total += (leftover % 2) * flipCost
        return total

