var minimumCost = function(s, t, flipCost, swapCost, crossCost) {
    let a = 0;
    let b = 0;
    for (let i = 0; i < s.length; i++) {
        if (s[i] === '0' && t[i] === '1') a++;
        else if (s[i] === '1' && t[i] === '0') b++;
    }
    const oppositePairCost = Math.min(swapCost, 2 * flipCost);
    let total = Math.min(a, b) * oppositePairCost;
    const leftover = Math.abs(a - b);
    const samePairCost = Math.min(2 * flipCost, swapCost + crossCost);
    total += Math.floor(leftover / 2) * samePairCost;
    total += (leftover % 2) * flipCost;
    return total;
};
